sql:
SELECT COUNT(*) AS mandatory_count
FROM obligations
WHERE obligation = 'Mandatory';

SELECT obligation
FROM obligations
WHERE data_element_id = 1;

SELECT name, version
FROM data_elements
ORDER BY name ASC;

